payload.text:
Untuk menghubungkan aplikasi React Anda dengan Google Spreadsheet sebagai database, kita tidak bisa langsung menggunakan URL Spreadsheet tersebut di dalam kode frontend karena alasan keamanan (CORS dan Autentikasi).

Solusinya adalah menggunakan **Google Apps Script** sebagai jembatan (API).

Berikut adalah langkah-langkah yang **HARUS** Anda lakukan terlebih dahulu pada Google Spreadsheet Anda, sebelum kode di bawah ini bisa berjalan:

### 1. Siapkan Google Spreadsheet
1. Buka link spreadsheet Anda: [Link Spreadsheet](https://docs.google.com/spreadsheets/d/1kb1olb-l-9EeX8nrRaW_rrbuRv1BkLVG6nbxVa32Ux4/edit?usp=sharing)
2. Buat 2 Sheet (Tab) di bagian bawah dengan nama persis:
   - **Laporan**
   - **MasterData**
3. Di sheet **Laporan**, buat header di baris 1: `id`, `json_data`.
4. Di sheet **MasterData**, buat header di baris 1: `ulp_name`, `json_data`.

### 2. Pasang Google Apps Script (Backend)
1. Di Spreadsheet, klik menu **Ekstensi** > **Apps Script**.
2. Hapus kode yang ada, lalu copy-paste kode berikut ini:

```javascript
// ID Spreadsheet Anda
var SPREADSHEET_ID = '1kb1olb-l-9EeX8nrRaW_rrbuRv1BkLVG6nbxVa32Ux4';

function doGet(e) {
  var action = e.parameter.action;

  if (action == 'getAll') {
    return getAllData();
  }
}

function doPost(e) {
  var contents = JSON.parse(e.postData.contents);
  var action = contents.action;

  if (action == 'saveReport') {
    return saveReport(contents.data);
  } else if (action == 'updateMaster') {
    return updateMaster(contents.data);
  }
}

function getAllData() {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);

  // Ambil Laporan
  var sheetLaporan = ss.getSheetByName('Laporan');
  var dataLaporan = sheetLaporan.getDataRange().getValues();
  var reports = [];
  // Skip header, mulai dari baris 2
  for (var i = 1; i < dataLaporan.length; i++) {
    if (dataLaporan[i][1]) {
      reports.push(JSON.parse(dataLaporan[i][1]));
    }
  }

  // Ambil Master Data
  var sheetMaster = ss.getSheetByName('MasterData');
  var dataMaster = sheetMaster.getDataRange().getValues();
  var masterData = {};

  // Jika kosong, kembalikan null agar frontend pakai default
  if (dataMaster.length <= 1) {
    return ContentService.createTextOutput(JSON.stringify({ reports: reports, masterData: null })).setMimeType(ContentService.MimeType.JSON);
  }

  for (var i = 1; i < dataMaster.length; i++) {
    if (dataMaster[i][0] && dataMaster[i][1]) {
      masterData[dataMaster[i][0]] = JSON.parse(dataMaster[i][1]);
    }
  }

  return ContentService.createTextOutput(JSON.stringify({ reports: reports, masterData: masterData })).setMimeType(ContentService.MimeType.JSON);
}

function saveReport(data) {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  var sheet = ss.getSheetByName('Laporan');
  // Simpan ID dan Full JSON Objek
  sheet.appendRow([data.id, JSON.stringify(data)]);
  return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
}

function updateMaster(fullMasterData) {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  var sheet = ss.getSheetByName('MasterData');

  // Clear data lama (kecuali header)
  if (sheet.getLastRow() > 1) {
    sheet.getRange(2, 1, sheet.getLastRow() - 1, 2).clearContent();
  }

  var rows = [];
  for (var key in fullMasterData) {
    rows.push([key, JSON.stringify(fullMasterData[key])]);
  }

  if (rows.length > 0) {
    sheet.getRange(2, 1, rows.length, 2).setValues(rows);
  }

  return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
}
```

3. Klik **Simpan** (Ikon Disket).
4. Klik tombol **Terapkan** (Deploy) > **Deployment Baru**.
5. Pilih jenis: **Aplikasi Web**.
6. Konfigurasi:
   - Deskripsi: `API Monitoring`
   - Jalankan sebagai: **Saya** (Email Anda).
   - Yang memiliki akses: **Siapa saja** (Anyone). <- *PENTING AGAR TIDAK PERLU LOGIN GOOGLE DI APP*
7. Klik **Terapkan**.
8. Salin **URL Aplikasi Web** (berakhiran `/exec`).

### 3. Update Kode Aplikasi (React)

Setelah Anda mendapatkan URL Deployment (Langkah 2.8), masukkan URL tersebut ke dalam file `services/api.ts` di bawah ini menggantikan `PASTE_YOUR_GOOGLE_SCRIPT_WEB_APP_URL_HERE`.

Berikut adalah pembaruan kode aplikasinya:

Karena pengaturan kolom Google Spreadsheet (Backend) berada di luar kode aplikasi React (Frontend), Anda **WAJIB** memperbarui script di Google Spreadsheet Anda agar data tersimpan rapi per kolom.

Berikut adalah langkah-langkah yang harus dilakukan:

### 1. Atur Header Kolom di Google Spreadsheet
Buka Sheet **'Laporan'** dan buat Header di **Baris 1** dengan urutan persis seperti ini:
1. `ID`
2. `Timestamp`
3. `Bulan`
4. `No Penugasan`
5. `ULP`
6. `Petugas 1`
7. `Petugas 2`
8. `Penyulang`
9. `Keypoint`
10. `Titik Start`
11. `Titik Finish`
12. `Foto Sebelum 1`
13. `Foto Sesudah 1`
14. `Foto Sebelum 2`
15. `Foto Sesudah 2`
16. `Foto Sebelum 3`
17. `Foto Sesudah 3`
18. `Foto Sebelum 4`
19. `Foto Sesudah 4`
20. `Foto Sebelum 5`
21. `Foto Sesudah 5`
22. `Foto Sebelum 6`
23. `Foto Sesudah 6`

### 2. Update Google Apps Script
1. Di Spreadsheet, buka **Ekstensi** > **Apps Script**.
2. **Hapus semua kode lama**, dan ganti dengan kode baru di bawah ini yang sudah disesuaikan untuk menyimpan data per kolom (bukan JSON blob lagi).

```javascript
// ID Spreadsheet Anda
var SPREADSHEET_ID = '1kb1olb-l-9EeX8nrRaW_rrbuRv1BkLVG6nbxVa32Ux4';

function doGet(e) {
  var action = e.parameter.action;
  if (action == 'getAll') {
    return getAllData();
  }
}

function doPost(e) {
  var contents = JSON.parse(e.postData.contents);
  var action = contents.action;
  if (action == 'saveReport') {
    return saveReport(contents.data);
  } else if (action == 'updateMaster') {
    return updateMaster(contents.data);
  }
}

function getAllData() {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);

  // --- AMBIL DATA LAPORAN (KOLOM) ---
  var sheetLaporan = ss.getSheetByName('Laporan');
  var dataLaporan = sheetLaporan.getDataRange().getValues();
  var reports = [];

  // Mulai baris ke-2 (Baris 1 adalah Header)
  for (var i = 1; i < dataLaporan.length; i++) {
    var row = dataLaporan[i];
    if (!row[0]) continue; // Skip jika ID kosong

    // Rekonstruksi Array Foto (Kolom 11 s/d 22, index 0-based)
    var photoSeb = [];
    var photoSes = [];
    for(var p=0; p<6; p++) {
       // Foto Sebelum ada di index ganjil mulai 11 (11, 13, 15...)
       // Foto Sesudah ada di index genap mulai 12 (12, 14, 16...)
       photoSeb.push(row[11 + (p*2)]);
       photoSes.push(row[12 + (p*2)]);
    }

    // Pastikan Timestamp string
    var ts = row[1];
    if (ts instanceof Date) { ts = ts.toISOString(); }

    var report = {
      id: String(row[0]),
      timestamp: ts,
      bulan: row[2],
      noPenugasan: row[3],
      ulp: row[4],
      petugas1: row[5],
      petugas2: row[6],
      penyulang: row[7],
      keypoint: row[8],
      titikStart: row[9],
      titikFinish: row[10],
      photos: {
        sebelum: photoSeb,
        sesudah: photoSes
      }
    };
    reports.push(report);
  }

  // --- AMBIL MASTER DATA ---
  var sheetMaster = ss.getSheetByName('MasterData');
  var dataMaster = sheetMaster.getDataRange().getValues();
  var masterData = {};
  for (var i = 1; i < dataMaster.length; i++) {
    if (dataMaster[i][0] && dataMaster[i][1]) {
      try {
        masterData[dataMaster[i][0]] = JSON.parse(dataMaster[i][1]);
      } catch(e) {}
    }
  }

  return ContentService.createTextOutput(JSON.stringify({ reports: reports, masterData: masterData })).setMimeType(ContentService.MimeType.JSON);
}

function saveReport(data) {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  var sheet = ss.getSheetByName('Laporan');

  // Siapkan Baris Data (Mapping Object ke Kolom)
  var row = [
    data.id,
    data.timestamp,
    data.bulan,
    data.noPenugasan,
    data.ulp,
    data.petugas1,
    data.petugas2,
    data.penyulang,
    data.keypoint,
    data.titikStart,
    data.titikFinish
  ];

  // Masukkan Foto secara selang-seling (Sebelum 1, Sesudah 1, Sebelum 2, dst)
  for(var i=0; i<6; i++) {
    row.push(data.photos.sebelum[i] || "");
    row.push(data.photos.sesudah[i] || "");
  }

  sheet.appendRow(row);
  return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
}

function updateMaster(fullMasterData) {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  var sheet = ss.getSheetByName('MasterData');
  if (sheet.getLastRow() > 1) {
    sheet.getRange(2, 1, sheet.getLastRow() - 1, 2).clearContent();
  }
  var rows = [];
  for (var key in fullMasterData) {
    rows.push([key, JSON.stringify(fullMasterData[key])]);
  }
  if (rows.length > 0) {
    sheet.getRange(2, 1, rows.length, 2).setValues(rows);
  }
  return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
}
```

3. Klik **Simpan** (Ikon Disket).
4. Klik **Terapkan (Deploy)** > **Deployment Baru** (atau Kelola Deployment > Edit > Versi Baru).
5. Pastikan akses tetap **"Siapa saja (Anyone)"**.
6. Klik **Terapkan**. Jika URL berubah, update di file `services/api.ts`.

### 3. Update Kode Aplikasi
Saya memperbarui file `services/api.ts` untuk mendokumentasikan struktur kolom ini agar jelas bagi pengembang selanjutnya.

Penyebab utama aplikasi belum bisa tersambung ke Spreadsheet biasanya karena **URL Penghubung (API URL)** di dalam kode aplikasi (`services/api.ts`) belum diganti dengan URL milik Anda sendiri, atau kode di Google Apps Script belum diperbarui/di-deploy dengan benar.

Agar tersambung, ikuti langkah **WAJIB** ini satu per satu:

### 1. Update Kode Google Apps Script (Backend)
Saya sudah menyiapkan kode yang **sudah berisi ID Spreadsheet dan ID Folder Drive Anda**. Anda tinggal Copy-Paste saja.

1.  Buka Google Spreadsheet Anda: [Link Spreadsheet](https://docs.google.com/spreadsheets/d/1kb1olb-l-9EeX8nrRaW_rrbuRv1BkLVG6nbxVa32Ux4/edit?usp=sharing)
2.  Menu **Ekstensi** > **Apps Script**.
3.  **Hapus semua kode yang ada**.
4.  **Copy-Paste** kode di bawah ini:

```javascript
// --- KONFIGURASI ---
// ID Spreadsheet Anda (Sudah diisi)
var SPREADSHEET_ID = '1kb1olb-l-9EeX8nrRaW_rrbuRv1BkLVG6nbxVa32Ux4';
// ID Folder Google Drive Anda (Sudah diisi)
var DRIVE_FOLDER_ID = '1zMK33wH2daWieijYsw3csJJtAXwwOGaj';

function doGet(e) {
  var action = e.parameter.action;
  if (action == 'getAll') {
    return getAllData();
  }
  return ContentService.createTextOutput("API Active");
}

function doPost(e) {
  try {
    var contents = JSON.parse(e.postData.contents);
    var action = contents.action;

    if (action == 'saveReport') {
      return saveReport(contents.data);
    } else if (action == 'updateMaster') {
      return updateMaster(contents.data);
    }
  } catch (error) {
     return ContentService.createTextOutput(JSON.stringify({ status: 'error', message: error.toString() })).setMimeType(ContentService.MimeType.JSON);
  }
}

function getAllData() {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);

  // --- AMBIL DATA LAPORAN ---
  var sheetLaporan = ss.getSheetByName('Laporan');
  var reports = [];

  // Cek jika sheet ada isinya (lebih dari header)
  if (sheetLaporan.getLastRow() > 1) {
    var dataLaporan = sheetLaporan.getDataRange().getValues();

    // Loop mulai baris ke-2 (index 1)
    for (var i = 1; i < dataLaporan.length; i++) {
      var row = dataLaporan[i];
      if (!row[0]) continue; // Skip jika ID kosong

      // Ambil Foto dari kolom 11 s/d 22 (index 0-based)
      var photoSeb = [];
      var photoSes = [];
      for(var p=0; p<6; p++) {
         photoSeb.push(row[11 + (p*2)]);
         photoSes.push(row[12 + (p*2)]);
      }

      var ts = row[1];
      if (ts instanceof Date) { ts = ts.toISOString(); }

      reports.push({
        id: String(row[0]),
        timestamp: ts,
        bulan: row[2],
        noPenugasan: row[3],
        ulp: row[4],
        petugas1: row[5],
        petugas2: row[6],
        penyulang: row[7],
        keypoint: row[8],
        titikStart: row[9],
        titikFinish: row[10],
        photos: { sebelum: photoSeb, sesudah: photoSes }
      });
    }
  }

  // --- AMBIL MASTER DATA ---
  var sheetMaster = ss.getSheetByName('MasterData');
  var masterData = {};
  if (sheetMaster && sheetMaster.getLastRow() > 1) {
    var dataMaster = sheetMaster.getDataRange().getValues();
    for (var i = 1; i < dataMaster.length; i++) {
      if (dataMaster[i][0] && dataMaster[i][1]) {
        try {
          masterData[dataMaster[i][0]] = JSON.parse(dataMaster[i][1]);
        } catch(e) {}
      }
    }
  }

  return ContentService.createTextOutput(JSON.stringify({ reports: reports, masterData: masterData })).setMimeType(ContentService.MimeType.JSON);
}

function uploadToDrive(folder, base64Data, fileName) {
  if (!base64Data || base64Data.length < 100) return "";
  // Jika sudah URL, kembalikan URL
  if (base64Data.indexOf("http") === 0) return base64Data;

  try {
    var contentType = base64Data.substring(5, base64Data.indexOf(';'));
    var bytes = Utilities.base64Decode(base64Data.substring(base64Data.indexOf('base64,') + 7));
    var blob = Utilities.newBlob(bytes, contentType, fileName);

    var file = folder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
    return file.getUrl();
  } catch (e) {
    return "Error Upload";
  }
}

function saveReport(data) {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  var sheet = ss.getSheetByName('Laporan');
  var folder = DriveApp.getFolderById(DRIVE_FOLDER_ID);

  var photosSebLinks = [];
  var photosSesLinks = [];

  // Proses Upload Foto
  for (var i = 0; i < 6; i++) {
     var safeNo = (data.noPenugasan || 'NoID').replace(/[^a-zA-Z0-9-_]/g, '_');
     var safeKP = (data.keypoint || 'KP').replace(/[^a-zA-Z0-9-_]/g, '_');
     var nameBase = safeNo + "_" + safeKP + "_Area" + (i+1);

     var linkSeb = uploadToDrive(folder, data.photos.sebelum[i], nameBase + "_SBLM.jpg");
     var linkSes = uploadToDrive(folder, data.photos.sesudah[i], nameBase + "_SSDH.jpg");

     photosSebLinks.push(linkSeb);
     photosSesLinks.push(linkSes);
  }

  var row = [
    data.id,
    data.timestamp,
    data.bulan,
    data.noPenugasan,
    data.ulp,
    data.petugas1,
    data.petugas2,
    data.penyulang,
    data.keypoint,
    data.titikStart,
    data.titikFinish
  ];

  // Tambahkan Link Foto ke baris
  for(var i=0; i<6; i++) {
    row.push(photosSebLinks[i]);
    row.push(photosSesLinks[i]);
  }

  sheet.appendRow(row);
  return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
}

function updateMaster(fullMasterData) {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  var sheet = ss.getSheetByName('MasterData');

  // Bersihkan data lama
  if (sheet.getLastRow() > 1) {
    sheet.getRange(2, 1, sheet.getLastRow() - 1, 2).clearContent();
  }

  var rows = [];
  for (var key in fullMasterData) {
    rows.push([key, JSON.stringify(fullMasterData[key])]);
  }

  if (rows.length > 0) {
    sheet.getRange(2, 1, rows.length, 2).setValues(rows);
  }
  return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
}
```

### 2. Deploy Web App (PENTING!)
Setelah Paste kode di atas:
1.  Klik **Simpan** (Ikon Disket).
2.  Klik tombol biru **Terapkan (Deploy)** di pojok kanan atas -> **Deployment Baru**.
3.  Pilih jenis: **Aplikasi Web** (roda gigi sebelah kiri).
4.  Konfigurasi:
    *   Deskripsi: `Versi 2`
    *   Jalankan sebagai: **Saya** (Email Anda).
    *   Yang memiliki akses: **Siapa saja** (Anyone). **<- WAJIB PILIH INI**
5.  Klik **Terapkan**.
6.  Salin **URL Aplikasi Web** yang muncul (berakhiran `/exec`).

### 3. Masukkan URL ke Aplikasi
Ganti `MASUKKAN_URL_DEPLOYMENT_ANDA_DISINI` di dalam file `services/api.ts` di bawah ini dengan URL yang baru saja Anda salin.
